code.C:
#include <stdio.h>
#include <stdlib.h>
int main(){
    ios:
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char *s = (char*)malloc(N+5);
        scanf("%s", s);
        printf("%d\n", N/2);
        free(s);
    }
    return 0;
}

